import express from "express";
import path from "path";
import fs from "fs";
import { createServer as createViteServer } from "vite";

async function startServer() {
  const app = express();
  const PORT = 3000;

  // Middleware
  app.use(express.json());

  // Slugify helper
  function slugify(text: string) {
    return text
      .toString()
      .toLowerCase()
      .trim()
      .replace(/\s+/g, '-')           // Replace spaces with -
      .replace(/[^\w\-]+/g, '')       // Remove all non-word chars
      .replace(/\-\-+/g, '-');         // Replace multiple - with single -
  }

  // Indonesian date formatter helper
  function formatIdnDate(d: Date) {
    const months = [
      "Januari", "Februari", "Maret", "April", "Mei", "Juni",
      "Juli", "Agustus", "September", "Oktober", "November", "Desember"
    ];
    return `${d.getDate()} ${months[d.getMonth()]} ${d.getFullYear()}`;
  }

  // API endpoints FIRST
  app.get("/api/download/zip", (req, res) => {
    const filePath = path.join(process.cwd(), "project.zip");
    if (fs.existsSync(filePath)) {
      res.download(filePath, "project.zip");
    } else {
      res.status(404).send("File project.zip tidak ditemukan. Silakan lakukan 'npm run build' terlebih dahulu untuk generate.");
    }
  });

  app.get("/api/seo-config", (req, res) => {
    const filePath = path.join(process.cwd(), "seo-config.json");
    const publicPath = path.join(process.cwd(), "public", "seo-config.json");
    if (fs.existsSync(filePath)) {
      res.json(JSON.parse(fs.readFileSync(filePath, "utf-8")));
    } else if (fs.existsSync(publicPath)) {
      res.json(JSON.parse(fs.readFileSync(publicPath, "utf-8")));
    } else {
      res.json({});
    }
  });

  app.post("/api/seo-config", (req, res) => {
    try {
      const config = req.body;
      const filePath = path.join(process.cwd(), "seo-config.json");
      const publicPath = path.join(process.cwd(), "public", "seo-config.json");
      
      fs.writeFileSync(filePath, JSON.stringify(config, null, 2), "utf-8");
      
      if (!fs.existsSync(path.join(process.cwd(), "public"))) {
        fs.mkdirSync(path.join(process.cwd(), "public"), { recursive: true });
      }
      fs.writeFileSync(publicPath, JSON.stringify(config, null, 2), "utf-8");

      console.log("Successfully saved updated SEO configurations.");
      return res.json({ success: true });
    } catch (error: any) {
      console.error("Error saving SEO configuration:", error);
      return res.status(500).json({ error: error.message });
    }
  });

  app.get("/api/download/posts", (req, res) => {
    const filePath = path.join(process.cwd(), "posts.json");
    const publicPath = path.join(process.cwd(), "public", "posts.json");
    if (fs.existsSync(filePath)) {
      res.download(filePath, "posts.json");
    } else if (fs.existsSync(publicPath)) {
      res.download(publicPath, "posts.json");
    } else {
      res.status(404).send("File posts.json belum tersedia.");
    }
  });

  app.post("/api/posts", (req, res) => {
    try {
      const { title, excerpt, content, category, readTime, image } = req.body;

      if (!title || !excerpt || !content || !category || !readTime) {
        return res.status(400).json({ 
          error: "Field 'title', 'excerpt', 'content', 'category', dan 'readTime' wajib diisi!" 
        });
      }

      const publicPath = path.join(process.cwd(), "public", "posts.json");
      const rootPath = path.join(process.cwd(), "posts.json");

      let posts = [];

      // Determine existing posts
      if (fs.existsSync(publicPath)) {
        try {
          posts = JSON.parse(fs.readFileSync(publicPath, "utf-8"));
        } catch (e) {
          console.error("Error reading public/posts.json, resetting array");
        }
      } else if (fs.existsSync(rootPath)) {
        try {
          posts = JSON.parse(fs.readFileSync(rootPath, "utf-8"));
        } catch (e) {
          console.error("Error reading posts.json, resetting array");
        }
      }

      let id = slugify(title) || `post-${Date.now()}`;
      const idBase = id;
      let counter = 1;
      while (posts.some((p: any) => p.id === id)) {
        counter++;
        id = `${idBase}-${counter}`;
      }

      const date = formatIdnDate(new Date());

      const newPost = {
        id,
        title,
        excerpt,
        content,
        category,
        date,
        readTime,
        image: image || "https://images.unsplash.com/photo-1499750310107-5fef28a66643?auto=format&fit=crop&w=800&q=80"
      };

      // Prepend to show the latest post first
      posts.unshift(newPost);

      // Save back to both locations to ensure absolute consistency
      fs.writeFileSync(publicPath, JSON.stringify(posts, null, 2), "utf-8");
      fs.writeFileSync(rootPath, JSON.stringify(posts, null, 2), "utf-8");

      console.log(`Successfully added new post: ${title} (${id})`);
      return res.json({ success: true, post: newPost });
    } catch (error: any) {
      console.error("Error saving post:", error);
      return res.status(500).json({ 
        error: "Terjadi kesalahan internal ketika menyimpan artikel baru: " + error.message 
      });
    }
  });

  app.put("/api/posts/:id", (req, res) => {
    try {
      const { id } = req.params;
      const { title, excerpt, content, category, readTime, image } = req.body;

      if (!title || !excerpt || !content || !category || !readTime) {
        return res.status(400).json({ 
          error: "Field 'title', 'excerpt', 'content', 'category', dan 'readTime' wajib diisi!" 
        });
      }

      const publicPath = path.join(process.cwd(), "public", "posts.json");
      const rootPath = path.join(process.cwd(), "posts.json");

      let posts = [];

      if (fs.existsSync(publicPath)) {
        try {
          posts = JSON.parse(fs.readFileSync(publicPath, "utf-8"));
        } catch (e) {
          console.error("Error reading public/posts.json", e);
        }
      } else if (fs.existsSync(rootPath)) {
        try {
          posts = JSON.parse(fs.readFileSync(rootPath, "utf-8"));
        } catch (e) {
          console.error("Error reading posts.json", e);
        }
      }

      const postIndex = posts.findIndex((p: any) => p.id === id);
      if (postIndex === -1) {
        return res.status(404).json({ error: "Post tidak ditemukan" });
      }

      posts[postIndex] = {
        ...posts[postIndex],
        title,
        excerpt,
        content,
        category,
        readTime,
        image: image || "https://images.unsplash.com/photo-1499750310107-5fef28a66643?auto=format&fit=crop&w=800&q=80"
      };

      fs.writeFileSync(publicPath, JSON.stringify(posts, null, 2), "utf-8");
      fs.writeFileSync(rootPath, JSON.stringify(posts, null, 2), "utf-8");

      console.log(`Successfully updated post: ${id}`);
      return res.json({ success: true, post: posts[postIndex] });
    } catch (error: any) {
      console.error("Error updating post:", error);
      return res.status(500).json({ 
        error: "Terjadi kesalahan ketika memperbarui artikel: " + error.message 
      });
    }
  });

  app.delete("/api/posts/:id", (req, res) => {
    try {
      const { id } = req.params;

      const publicPath = path.join(process.cwd(), "public", "posts.json");
      const rootPath = path.join(process.cwd(), "posts.json");

      let posts = [];

      if (fs.existsSync(publicPath)) {
        try {
          posts = JSON.parse(fs.readFileSync(publicPath, "utf-8"));
        } catch (e) {
          console.error("Error reading public/posts.json", e);
        }
      } else if (fs.existsSync(rootPath)) {
        try {
          posts = JSON.parse(fs.readFileSync(rootPath, "utf-8"));
        } catch (e) {
          console.error("Error reading posts.json", e);
        }
      }

      const filteredPosts = posts.filter((p: any) => p.id !== id);
      if (posts.length === filteredPosts.length) {
        return res.status(404).json({ error: "Post tidak ditemukan" });
      }

      fs.writeFileSync(publicPath, JSON.stringify(filteredPosts, null, 2), "utf-8");
      fs.writeFileSync(rootPath, JSON.stringify(filteredPosts, null, 2), "utf-8");

      console.log(`Successfully deleted post: ${id}`);
      return res.json({ success: true });
    } catch (error: any) {
      console.error("Error deleting post:", error);
      return res.status(500).json({ 
        error: "Terjadi kesalahan ketika menghapus artikel: " + error.message 
      });
    }
  });

  // Vite integration
  if (process.env.NODE_ENV !== "production") {
    console.log("Starting server in development mode with Vite middleware...");
    const vite = await createViteServer({
      server: { middlewareMode: true },
      appType: "spa",
    });
    // Serve local images folder in development
    app.use("/img", express.static(path.join(process.cwd(), "img")));
    app.use(vite.middlewares);
  } else {
    console.log("Starting server in production mode...");
    const distPath = path.join(process.cwd(), "dist");
    app.use(express.static(distPath));
    app.get("*", (req, res) => {
      res.sendFile(path.join(distPath, "index.html"));
    });
  }

  app.listen(PORT, "0.0.0.0", () => {
    console.log(`Server is running at http://localhost:${PORT}`);
  });
}

startServer();
